// food-utils.js
function normalizeFoodKey(name) {
  return String(name || "").toLowerCase().replace(/^[•\-\*]\s*/, "").replace(/\([^)]*\)/g, " ").replace(/\[[^\]]*\]/g, " ").replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();
}

// food-catalog-data.js
function item(id, name, nutritionKey, group, slots, timing, universality, opts = {}) {
  const defaultVeg = ["vegetable", "carb", "fat", "fruit", "legume", "condiment", "beverage"].includes(group) || group === "dairy" || group === "ready_meal" && !opts.meat;
  return {
    id,
    name,
    nutritionKey,
    group,
    slots,
    timing,
    universality,
    vegan: !!opts.vegan,
    vegetarian: opts.vegetarian !== void 0 ? !!opts.vegetarian : defaultVeg,
    genericOf: opts.genericOf || null,
    aliases: opts.aliases || []
  };
}
