    emphasis: ["\u0417\u0435\u043B\u0435\u043D \u0447\u0430\u0439", "\u041A\u0443\u0440\u043A\u0443\u043C\u0430", "\u041A\u044A\u043F\u0438\u043D\u0438 \u0438 \u0433\u043E\u0440\u0441\u043A\u0438 \u043F\u043B\u043E\u0434\u043E\u0432\u0435", "\u0417\u0435\u0445\u0442\u0438\u043D \u0435\u043A\u0441\u0442\u0440\u0430 \u0432\u044A\u0440\u0434\u0436\u0438\u043D", "\u0412\u0438\u0441\u043E\u043A\u043E \u0444\u0438\u0431\u0440\u043E\u0432\u0438 \u0445\u0440\u0430\u043D\u0438", "\u041E\u043C\u0435\u0433\u0430-3 \u0440\u0438\u0431\u0438"],
