      "\u{1F48A} NAC \u043D\u0430\u043C\u0430\u043B\u044F\u0432\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u0442\u043E \u0437\u0430 \u0442\u044E\u0442\u044E\u043D\u043E\u043F\u0443\u0448\u0435\u043D\u0435 \u2014 \u0434\u043E\u043A\u0430\u0437\u0430\u043D\u043E \u0432 \u043A\u043B\u0438\u043D\u0438\u0447\u043D\u0438 \u043F\u0440\u043E\u0443\u0447\u0432\u0430\u043D\u0438\u044F",
