async function retryWithBackoff(fn, maxRetries = 3, initialDelay = 1e3) {
  let lastError;
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;
      const errorMessage = error.message || "";
      const isRetryable = errorMessage.includes("502") || // Bad Gateway
      errorMessage.includes("503") || // Service Unavailable
      errorMessage.includes("504") || // Gateway Timeout
      errorMessage.includes("429") || // Too Many Requests
      errorMessage.includes("ECONNRESET") || errorMessage.includes("ETIMEDOUT") || errorMessage.includes("network");
      if (!isRetryable || attempt === maxRetries - 1) {
        throw error;
      }
      const delay = initialDelay * Math.pow(2, attempt);
      const safeErrorMessage = errorMessage.replace(/(?:key|token|auth|bearer)[=:]\s*[^\s&]+/gi, (match) => {
        return match.split(/[=:]/)[0] + "=***";
      });
      console.log(`Retry attempt ${attempt + 1}/${maxRetries} after ${delay}ms due to: ${safeErrorMessage}`);
      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  }
  throw lastError;
}
