        logText += "\n[ \u041F\u0420\u041E\u041C\u041F\u0422 ]\n";
        logText += (req.prompt || "(\u043D\u0435 \u0435 \u0437\u0430\u043F\u0430\u0437\u0435\u043D)") + "\n";
