async function handleAddToBlacklist(request, env) {
  try {
    const data = await request.json();
    const item2 = data.item?.trim()?.toLowerCase();
    const mode = data.mode === "substitute" ? "substitute" : "ban";
    const substitute = mode === "substitute" ? data.substitute?.trim() || "" : void 0;
    if (!item2) {
      return jsonResponse2({ error: "Item is required" }, 400);
    }
    if (mode === "substitute" && !substitute) {
      return jsonResponse2({ error: "Substitute is required when mode is substitute" }, 400);
    }
    if (!env.page_content) {
      return jsonResponse2({ error: ERROR_MESSAGES.KV_NOT_CONFIGURED }, 500);
    }
    const blacklistData = await env.page_content.get("food_blacklist");
    let blacklist = blacklistData ? JSON.parse(blacklistData) : DEFAULT_FOOD_BLACKLIST;
    blacklist = blacklist.map(normalizeBlacklistEntry);
    const existing = blacklist.findIndex((e) => e.item === item2);
    const entry = mode === "substitute" ? { item: item2, mode, substitute } : { item: item2, mode };
    if (existing >= 0) {
      blacklist[existing] = entry;
    } else {
      blacklist.push(entry);
    }
    await env.page_content.put("food_blacklist", JSON.stringify(blacklist));
    invalidateFoodListsCache();
    return jsonResponse2({ success: true, blacklist });
  } catch (error) {
    console.error("Error adding to blacklist:", error);
    return jsonResponse2({ error: `Failed to add to blacklist: ${error.message}` }, 500);
  }
}
