async function handleUploadProtocolImage(request, env) {
  try {
    const body = await request.json();
    const { protocolId, imageData, mimeType } = body;
    if (!protocolId || !imageData) {
      return jsonResponse2({ error: "Protocol ID and image data are required" }, 400);
    }
    const validProtocols = [
      "insulin_resistance",
      "autoimmune_aip",
      "gi_issues",
      "menopause_sarcopenia",
      "cellulite_reduction",
      "chronic_stress",
      "postpartum_lactation",
      "visceral_fat",
      "post_smoking",
      "longevity",
      "detox"
    ];
    if (!validProtocols.includes(protocolId)) {
      return jsonResponse2({ error: "Invalid protocol ID" }, 400);
    }
    const allowedMimeTypes = ["image/png", "image/jpeg", "image/webp"];
    if (!mimeType || !allowedMimeTypes.includes(mimeType)) {
      return jsonResponse2({ error: "Invalid or missing image type. Allowed: PNG, JPG, WebP" }, 400);
    }
    if (!imageData.startsWith("data:image/")) {
      return jsonResponse2({ error: "Invalid image data format" }, 400);
    }
    const base64Data = imageData.split(",")[1] || "";
    const approximateSize = base64Data.length * 3 / 4;
    const maxSizeBytes = 500 * 1024;
    if (approximateSize > maxSizeBytes) {
      return jsonResponse2({ error: `Image too large. Maximum size: 500KB (received ~${Math.round(approximateSize / 1024)}KB)` }, 400);
    }
    if (!env || !env.page_content) {
      return jsonResponse2({ error: "Storage not available" }, 500);
    }
    const imagesStr = await env.page_content.get(PROTOCOL_IMAGES_KEY);
    let images = {};
    if (imagesStr) {
      try {
        images = JSON.parse(imagesStr);
      } catch (parseError) {
        console.error("Error parsing protocol images JSON, starting fresh:", parseError);
      }
    }
    images[protocolId] = imageData;
    await env.page_content.put(PROTOCOL_IMAGES_KEY, JSON.stringify(images));
    return jsonResponse2({
      success: true,
      imageUrl: imageData,
      message: "Image uploaded successfully"
    });
  } catch (error) {
    console.error("Error uploading protocol image:", error);
    return jsonResponse2({ error: `Failed to upload protocol image: ${error.message}` }, 500);
  }
}
async function handleDeleteProtocolImage(request, env) {
  try {
    const body = await request.json();
    const { protocolId } = body;
    if (!protocolId) {
      return jsonResponse2({ error: "Protocol ID is required" }, 400);
    }
    if (!env || !env.page_content) {
      return jsonResponse2({ error: "Storage not available" }, 500);
    }
    const imagesStr = await env.page_content.get(PROTOCOL_IMAGES_KEY);
    let images = {};
    if (imagesStr) {
      try {
        images = JSON.parse(imagesStr);
      } catch (parseError) {
        console.error("Error parsing protocol images JSON:", parseError);
      }
    }
    if (images[protocolId]) {
      delete images[protocolId];
      await env.page_content.put(PROTOCOL_IMAGES_KEY, JSON.stringify(images));
    }
    return jsonResponse2({ success: true, message: "Image deleted successfully" });
  } catch (error) {
    console.error("Error deleting protocol image:", error);
    return jsonResponse2({ error: `Failed to delete protocol image: ${error.message}` }, 500);
  }
}
