async function handleAIXChat(request, env) {
  if (!env.OPEN_ROUTER) {
    return jsonResponse2({ error: "OpenRouter API key not configured" }, 500);
  }
  let body;
  try {
    body = await request.json();
  } catch {
    return jsonResponse2({ error: "Invalid JSON" }, 400);
  }
  const { model, messages, systemPrompt, stream } = body;
  if (!Array.isArray(messages) || messages.length === 0) {
    return jsonResponse2({ error: "messages required" }, 400);
  }
  const apiMessages = systemPrompt ? [{ role: "system", content: systemPrompt }, ...messages] : messages;
  const orRes = await fetch("https://openrouter.ai/api/v1/chat/completions", {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${env.OPEN_ROUTER}`,
      "Content-Type": "application/json",
      "HTTP-Referer": "https://aidiet.radilov-k.workers.dev",
      "X-Title": "AIX"
    },
    body: JSON.stringify({
      model: model || "google/gemma-4-31b-it:free",
      messages: apiMessages,
      max_tokens: 2048,
      stream: stream === true
    })
  });
  if (!orRes.ok) {
    const err = await orRes.text();
    return jsonResponse2({ error: err }, orRes.status);
  }
  if (stream === true) {
    return new Response(orRes.body, {
      headers: {
        ...CORS_HEADERS2,
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        "X-Accel-Buffering": "no"
      }
    });
  }
  const data = await orRes.json();
  const content = data.choices?.[0]?.message?.content || "";
  return jsonResponse2({ content, usage: data.usage });
}
var XBODY_APPT_CACHE_TTL_SEC = 3600;
function computeXbodyApptVersion(upcoming, past) {
  const parts = [];
  for (const item2 of [...upcoming || [], ...past || []]) {
    parts.push(String(item2.id) + ":" + (item2.datetime || "") + ":" + (item2.canceled ? "1" : "0"));
  }
  parts.sort();
  const str = parts.join("|");
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = (hash << 5) - hash + str.charCodeAt(i) | 0;
  }
  return "v" + (hash >>> 0).toString(36);
}
async function handleXbodyAppointmentsVersion(request, env) {
  const url = new URL(request.url);
  const email = String(url.searchParams.get("email") || "").trim().toLowerCase();
  if (!email || !email.includes("@")) {
    return jsonResponse2({ error: "\u041B\u0438\u043F\u0441\u0432\u0430 \u0432\u0430\u043B\u0438\u0434\u0435\u043D \u0438\u043C\u0435\u0439\u043B." }, 400);
  }
  if (!env.page_content) {
    return jsonResponse2({ version: null, fetchedAt: null });
  }
  try {
    const cached = await env.page_content.get(`xbody:appt:${email}`);
    if (!cached) {
      return jsonResponse2({ version: null, fetchedAt: null }, 200, { cacheControl: "private, no-cache" });
    }
    const payload = JSON.parse(cached);
    const version = payload.version || computeXbodyApptVersion(payload.upcoming, payload.past);
    return jsonResponse2({
      version,
      fetchedAt: payload.fetchedAt || null
    }, 200, { cacheControl: "private, no-cache" });
  } catch (err) {
    console.warn("[xbody-appointments] version check failed:", err.message);
    return jsonResponse2({ version: null, fetchedAt: null }, 200, { cacheControl: "private, no-cache" });
  }
}
async function handleXbodyAppointments(request, env) {
  const userId = env.ACUITY_USER_ID;
  const apiKey = env.ACUITY_API_KEY;
  if (!userId || !apiKey) {
    return jsonResponse2({ error: "Acuity API \u043D\u0435 \u0435 \u043A\u043E\u043D\u0444\u0438\u0433\u0443\u0440\u0438\u0440\u0430\u043D." }, 503);
  }
  const url = new URL(request.url);
  const email = String(url.searchParams.get("email") || "").trim().toLowerCase();
  if (!email || !email.includes("@")) {
    return jsonResponse2({ error: "\u041B\u0438\u043F\u0441\u0432\u0430 \u0432\u0430\u043B\u0438\u0434\u0435\u043D \u0438\u043C\u0435\u0439\u043B." }, 400);
  }
  const forceRefresh = url.searchParams.get("refresh") === "1";
  const cacheKey = `xbody:appt:${email}`;
  if (!forceRefresh && env.page_content) {
    try {
      const cached = await env.page_content.get(cacheKey);
      if (cached) {
        const payload2 = JSON.parse(cached);
        if (!payload2.version) {
          payload2.version = computeXbodyApptVersion(payload2.upcoming, payload2.past);
        }
        return jsonResponse2(payload2, 200, { cacheControl: "private, max-age=300" });
      }
    } catch (err) {
      console.warn("[xbody-appointments] KV cache read failed:", err.message);
    }
  }
  const acuityUrl = new URL("https://acuityscheduling.com/api/v1/appointments");
  acuityUrl.searchParams.set("email", email);
  acuityUrl.searchParams.set("showall", "true");
  acuityUrl.searchParams.set("max", "40");
  acuityUrl.searchParams.set("direction", "DESC");
  acuityUrl.searchParams.set("excludeForms", "true");
  const auth = btoa(`${userId}:${apiKey}`);
  let resp;
  try {
    resp = await fetch(acuityUrl.toString(), {
      headers: { Authorization: `Basic ${auth}` }
    });
  } catch (err) {
    console.error("[xbody-appointments] fetch error:", err.message);
    return jsonResponse2({ error: "\u041D\u0435\u0443\u0441\u043F\u0435\u0448\u043D\u0430 \u0432\u0440\u044A\u0437\u043A\u0430 \u0441 Acuity." }, 502);
  }
  if (!resp.ok) {
    const body = await resp.text().catch(() => "");
    console.error("[xbody-appointments] Acuity error:", resp.status, body.slice(0, 200));
    return jsonResponse2({ error: "\u0413\u0440\u0435\u0448\u043A\u0430 \u043F\u0440\u0438 \u0437\u0430\u0440\u0435\u0436\u0434\u0430\u043D\u0435 \u043D\u0430 \u0440\u0435\u0437\u0435\u0440\u0432\u0430\u0446\u0438\u0438\u0442\u0435." }, resp.status === 401 ? 503 : 502);
  }
  const appointments = await resp.json();
  if (!Array.isArray(appointments)) {
    return jsonResponse2({ error: "\u041D\u0435\u043E\u0447\u0430\u043A\u0432\u0430\u043D \u043E\u0442\u0433\u043E\u0432\u043E\u0440 \u043E\u0442 Acuity." }, 502);
  }
  const now = Date.now();
  const upcoming = [];
  const past = [];
  for (const appt of appointments) {
    const item2 = {
      id: appt.id,
      date: appt.date || "",
      time: (appt.time || "").trim(),
      endTime: (appt.endTime || "").trim(),
      datetime: appt.datetime || "",
      type: appt.type || "\u0427\u0430\u0441",
      duration: appt.duration || "",
      calendar: appt.calendar || "",
      location: appt.location || "",
      canceled: Boolean(appt.canceled),
      canClientCancel: Boolean(appt.canClientCancel),
      canClientReschedule: Boolean(appt.canClientReschedule),
      confirmationPage: appt.confirmationPage || ""
    };
    const when = item2.datetime ? new Date(item2.datetime).getTime() : NaN;
    if (!item2.canceled && Number.isFinite(when) && when >= now) {
      upcoming.push(item2);
    } else {
      past.push(item2);
    }
  }
  upcoming.sort((a, b) => new Date(a.datetime).getTime() - new Date(b.datetime).getTime());
  const payload = {
    upcoming,
    past,
    fetchedAt: Date.now(),
    version: computeXbodyApptVersion(upcoming, past)
  };
  if (env.page_content) {
    try {
      await env.page_content.put(cacheKey, JSON.stringify(payload), {
        expirationTtl: XBODY_APPT_CACHE_TTL_SEC
      });
    } catch (err) {
      console.warn("[xbody-appointments] KV cache write failed:", err.message);
    }
  }
  return jsonResponse2(payload, 200, { cacheControl: "private, max-age=300" });
}
function isFitnessRoute(pathname, method) {
  if (method === "GET" && (pathname === "/api/health" || pathname === "/api/exercises/search")) return true;
  if (method === "GET" && pathname === "/api/admin/fitplan/guidelines") return true;
  if (method === "GET" && pathname === "/api/admin/fitplan/translate-exercises") return true;
  if (method === "GET" && pathname === "/api/admin/fitplan/consultations") return true;
  if (method === "GET" && pathname === "/api/admin/fitplan/consult-config") return true;
  if (method === "GET" && pathname === "/api/admin/fitplan/client-programs") return true;
  if (method === "DELETE" && /^\/api\/admin\/fitplan\/client-programs\/[A-Za-z0-9_-]+$/.test(pathname)) return true;
  if (method === "POST" && /^\/api\/admin\/fitplan\/client-programs\/[A-Za-z0-9_-]+\/delete$/.test(pathname)) return true;
  if (method === "POST" && (pathname === "/api/plan/generate" || pathname === "/api/plan/refresh-exercises" || pathname === "/api/fitplan/consultation" || pathname === "/api/coach" || pathname === "/api/admin/fitplan/guidelines" || pathname === "/api/admin/fitplan/translate-exercises" || pathname === "/api/admin/fitplan/consult-config" || pathname === "/api/admin/fitplan/client-programs" || /^\/api\/admin\/fitplan\/consultations\/[A-Za-z0-9_-]+\/read$/.test(pathname) || /^\/api\/admin\/fitplan\/client-programs\/[A-Za-z0-9_-]+\/(generate|approve)$/.test(pathname))) return true;
  if (method === "GET" && /^\/api\/plan\/[A-Za-z0-9-]{8,64}$/.test(pathname)) return true;
  return false;
}
